import{_ as s,c as e,o as n,a1 as l}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"高度: スキルエコシステム管理 | opencode-agent-skills","description":"opencode-agent-skills の高度な機能を習得。Claude Code 互換性、Superpowers 統合、名前空間とコンテキスト圧縮メカニズムを理解し、スキル管理能力を向上させます。","frontmatter":{"title":"高度: スキルエコシステム管理 | opencode-agent-skills","sidebarTitle":"複雑なスキルエコシステムをマスターする","subtitle":"高度な機能","order":3,"description":"opencode-agent-skills の高度な機能を習得。Claude Code 互換性、Superpowers 統合、名前空間とコンテキスト圧縮メカニズムを理解し、スキル管理能力を向上させます。","tags":["opencode-agent-skills","高度機能","Claude Code","Superpowers"],"prerequisite":["[OpenCode Agent Skills のインストール](../start/installation/)","[最初のスキルを作成する](../start/creating-your-first-skill/)","[スキル検出メカニズム](../platforms/skill-discovery-mechanism/)","[スキルをコンテキストに読み込む](../platforms/loading-skills-into-context/)"]},"headers":[],"relativePath":"ja/joshuadavidthomas/opencode-agent-skills/advanced/index.md","filePath":"ja/joshuadavidthomas/opencode-agent-skills/advanced/index.md"}'),i={name:"ja/joshuadavidthomas/opencode-agent-skills/advanced/index.md"};function p(o,a,t,r,d,c){return n(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="高度な機能" tabindex="-1">高度な機能 <a class="header-anchor" href="#高度な機能" aria-label="Permalink to &quot;高度な機能&quot;">​</a></h1><p>本章では、OpenCode Agent Skills の高度な機能について詳しく解説します。Claude Code 互換性、Superpowers ワークフロー統合、名前空間優先度システム、コンテキスト圧縮復元メカニズムなどを含みます。これらを習得することで、複雑なスキルエコシステムをより効果的に管理し、長時間のセッション中でもスキルが常に利用可能であることを保証できます。</p><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">開始前の確認</p><p>本章を学習する前に、以下が完了していることを確認してください：</p><ul><li><a href="./../start/installation/">OpenCode Agent Skills のインストール</a> - プラグインが正しくインストールされ、実行されていること</li><li><a href="./../start/creating-your-first-skill/">最初のスキルを作成する</a> - スキルの基本構造を理解していること</li><li><a href="./../platforms/skill-discovery-mechanism/">スキル検出メカニズムの詳細</a> - スキルがどの場所から検出されるかを理解していること</li><li><a href="./../platforms/loading-skills-into-context/">スキルをコンテキストに読み込む</a> - <code>use_skill</code> ツールの使用方法を習得していること</li></ul></div><h2 id="本章の内容" tabindex="-1">本章の内容 <a class="header-anchor" href="#本章の内容" aria-label="Permalink to &quot;本章の内容&quot;">​</a></h2><div class="grid-cards"><a href="./claude-code-compatibility/" class="card"><h3>Claude Code スキル互換性</h3><p>プラグインが Claude Code のスキルおよびプラグインシステムとどのように互換性を持つかを理解し、ツールマッピングメカニズムを習得し、Claude のスキルエコシステムを再利用します。</p></a><a href="./superpowers-integration/" class="card"><h3>Superpowers ワークフロー統合</h3><p>Superpowers モードを設定・使用し、厳格なソフトウェア開発ワークフロー指導を得て、開発効率とコード品質を向上させます。</p></a><a href="./namespaces-and-priority/" class="card"><h3>名前空間とスキル優先度</h3><p>スキルの名前空間システムと検出優先度ルールを理解し、同名スキルの競合を解決し、スキルソースを正確に制御します。</p></a><a href="./context-compaction-resilience/" class="card"><h3>コンテキスト圧縮復元メカニズム</h3><p>スキルが長時間のセッション中でどのように可用性を維持するかを理解し、圧縮復元のトリガー条件と実行フローを習得します。</p></a></div><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                           推奨学習順序                                   │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                                                         │</span></span>
<span class="line"><span>│   1. Claude Code 互換  ──→  2. Superpowers 統合  ──→  3. 名前空間       │</span></span>
<span class="line"><span>│         │                        │                        │             │</span></span>
<span class="line"><span>│         ▼                        ▼                        ▼             │</span></span>
<span class="line"><span>│   Claude スキルを再利用     ワークフロー指導を有効化    スキルソースを正確に制御 │</span></span>
<span class="line"><span>│                                                                         │</span></span>
<span class="line"><span>│                                  │                                      │</span></span>
<span class="line"><span>│                                  ▼                                      │</span></span>
<span class="line"><span>│                                                                         │</span></span>
<span class="line"><span>│                         4. コンテキスト圧縮復元                          │</span></span>
<span class="line"><span>│                                  │                                      │</span></span>
<span class="line"><span>│                                  ▼                                      │</span></span>
<span class="line"><span>│                         長時間セッションでのスキル永続化                   │</span></span>
<span class="line"><span>│                                                                         │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>順序を守って学習することをお勧めします</strong>：</p><ol><li><strong>まず Claude Code 互換性</strong> - Claude Code のスキルをお持ちの場合、または Claude プラグインマーケットのスキルを使用したい場合、これが第一歩です</li><li><strong>次に Superpowers 統合</strong> - 厳格なワークフロー指導を希望するユーザーは、有効化と設定方法を学びます</li><li><strong>その後名前空間</strong> - スキル数が増え、同名の競合が発生した場合、この知識が重要になります</li><li><strong>最後に圧縮復元</strong> - 長時間セッション中でスキルがどのように可用性を維持するかを理解します。より原理的な内容です</li></ol><div class="tip custom-block"><p class="custom-block-title">必要に応じて学習</p><ul><li><strong>Claude Code からの移行</strong>：第 1 課（互換性）と第 3 課（名前空間）に焦点を当ててください</li><li><strong>ワークフロー規範を希望</strong>：第 2 課（Superpowers）に焦点を当ててください</li><li><strong>スキル競合に遭遇</strong>：第 3 課（名前空間）を直接参照してください</li><li><strong>長時間セッションでスキルが失われる</strong>：第 4 課（圧縮復元）を直接参照してください</li></ul></div><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>本章を完了したら、以下を続けて学習できます：</p><ul><li><a href="./../faq/troubleshooting/">トラブルシューティング</a> - 問題が発生した場合は、故障排除ガイドを参照してください</li><li><a href="./../faq/security-considerations/">セキュリティに関する考慮事項</a> - プラグインのセキュリティメカニズムとベストプラクティスを理解してください</li><li><a href="./../appendix/api-reference/">API ツールリファレンス</a> - 利用可能なすべてのツールの詳細なパラメータと戻り値を確認してください</li><li><a href="./../appendix/best-practices/">スキル開発のベストプラクティス</a> - 高品質なスキルを作成するためのテクニックと規範を習得してください</li></ul>`,14)])])}const g=s(i,[["render",p]]);export{h as __pageData,g as default};
